import com.pinterest.ktlint.rule.engine.api.Code
import com.pinterest.ktlint.rule.engine.api.KtLintRuleEngine
import com.pinterest.ktlint.rule.engine.core.api.ElementType.BLOCK
import com.pinterest.ktlint.rule.engine.core.api.ElementType.FUN
import com.pinterest.ktlint.rule.engine.core.api.ElementType.LBRACE
import com.pinterest.ktlint.rule.engine.core.api.ElementType.WHITE_SPACE
import org.assertj.core.api.Assertions.assertThat
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.junit.jupiter.api.Test

internal class ASTNodeExtensionWhitespaceRegressionTest {
    private val ktLintRuleEngine =
        KtLintRuleEngine(
            ruleProviders =
                setOf(
                    RuleProvider { DummyRule() },
                ),
        )

    @Test
    fun `Given a function without spacing before the body block when inserting whitespace before the opening brace then the whitespace is visible before the block`() {
        val code =
            """
            fun foo(){
                println("bar")
            }
            """.trimIndent()
        val fileASTNode = ktLintRuleEngine.transformToAst(Code.fromSnippet(code))
        val funNode = requireNotNull(fileASTNode.findChildByType(FUN))
        val blockNode = requireNotNull(funNode.findChildByType(BLOCK))
        val openingBrace = requireNotNull(blockNode.findChildByType(LBRACE))

        assertThat(blockNode.prevLeaf()?.elementType).isNotEqualTo(WHITE_SPACE)

        openingBrace.upsertWhitespaceBeforeMe(" ")

        val whitespaceBeforeBlock = blockNode.prevLeaf()
        assertThat(whitespaceBeforeBlock?.elementType).isEqualTo(WHITE_SPACE)
        assertThat(whitespaceBeforeBlock?.text).isEqualTo(" ")
    }

    private fun KtLintRuleEngine.transformToAst(code: String) = transformToAst(Code.fromSnippet(code))

    private open class DummyRule(
        val block: (node: ASTNode) -> Unit = {},
    ) : Rule(
            ruleId = RuleId("test:dummy-rule"),
            about = About(),
        ) {
        override fun beforeVisitChildNodes(
            node: ASTNode,
            autoCorrect: Boolean,
            emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
        ) {
            block(node)
        }
    }
}
